1573	func allowedHost(host string) bool {
1574		host = strings.ToLower(host)
1575	
1576		if host == "" || host == "localhost" {
1577			return true
1578		}
1579	
1580		if hostname, err := os.Hostname(); err == nil && host == strings.ToLower(hostname) {
1581			return true
1582		}
1583	
1584		tlds := []string{
1585			"localhost",
1586			"local",
1587			"internal",
1588		}
1589	
1590		// check if the host is a local TLD
1591		for _, tld := range tlds {
1592			if strings.HasSuffix(host, "."+tld) {
1593				return true
1594			}
1595		}
1596	
1597		return false
1598	}
