1467		dst := model.ParseName(r.Destination)
1468		if !dst.IsValid() {
1469			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("destination %q is invalid", r.Destination)})
1470			return
1471		}
1472		dst, err = getExistingName(dst)
1473		if err != nil {
1474			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
1475			return
1476		}
1477	
1478		if err := CopyModel(src, dst); errors.Is(err, os.ErrNotExist) {
1479			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model %q not found", r.Source)})
1480		} else if err != nil {
1481			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
1482		}
1483	}
