74	func (m *Manifest) RemoveLayers() error {
75		ms, err := Manifests(true)
76		if err != nil {
77			return err
78		}
79	
80		// Build set of digests still in use by other manifests
81		inUse := make(map[string]struct{})
82		for _, other := range ms {
83			for _, layer := range append(other.Layers, other.Config) {
84				if layer.Digest != "" {
85					inUse[layer.Digest] = struct{}{}
86				}
87			}
88		}
89	
90		// Remove layers not used by any other manifest
91		for _, layer := range append(m.Layers, m.Config) {
92			if layer.Digest == "" {
93				continue
94			}
95			if _, used := inUse[layer.Digest]; used {
96				continue
97			}
98			blob, err := BlobsPath(layer.Digest)
99			if err != nil {
100				return err
101			}
102			if err := os.Remove(blob); os.IsNotExist(err) {
103				slog.Debug("layer does not exist", "digest", layer.Digest)
104			} else if err != nil {
105				return err
106			}
107		}
108	
109		return nil
110	}

1055	func (s *Server) DeleteHandler(c *gin.Context) {
1056		var r api.DeleteRequest
1057		if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
1058			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
1059			return
1060		} else if err != nil {
1061			c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
1062			return
1063		}
1064	
1065		modelRef, err := parseNormalizePullModelRef(cmp.Or(r.Model, r.Name))
1066		if err != nil {
1067			switch {
1068			case errors.Is(err, errConflictingModelSource):
1069				c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
1070			case errors.Is(err, model.ErrUnqualifiedName):
1071				c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("name %q is invalid", cmp.Or(r.Model, r.Name))})
1072			default:
1073				c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
1074			}
1075			return
1076		}
1077	
1078		n, err := getExistingName(modelRef.Name)
1079		if err != nil {
1080			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
1081			return
1082		}
1083	
1084		m, err := manifest.ParseNamedManifest(n)
1085		if err != nil {
1086			switch {
1087			case os.IsNotExist(err):
1088				c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
1089			default:
1090				c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
1091			}
1092			return
1093		}
1094	
1095		if err := m.Remove(); err != nil {
1096			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
1097			return
1098		}
1099	
1100		if err := m.RemoveLayers(); err != nil {
1101			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
1102			return
1103		}
1104	}
